# Pattern: embed label values directly into the dashboard URL
dashboard_url: >-
  https://grafana.example.com/d/genai-triage/incident-triage
  ?var-env={{ $labels.env }}
  &var-model={{ $labels.model }}
  &var-region={{ $labels.region }}
  &from={{ $labels.__alert_start_time__ }}
  &to=now

#!/usr/bin/env python3
# scripts/check_runbook_links.py
import sys, re, yaml, requests
from pathlib import Path

ALERT_DIR = Path("alerts/")
TIMEOUT_S = 5

def load_all_alerts(alert_dir: Path) -> list[dict]:
    alerts = []
    for f in alert_dir.rglob("*.yaml"):
        docs = yaml.safe_load_all(f.read_text())
        for doc in docs:
            for group in (doc or {}).get("groups", []):
                for rule in group.get("rules", []):
                    if "alert" in rule:
                        rule["_file"] = str(f)
                        alerts.append(rule)
    return alerts

def check_runbook_links(alerts: list[dict]) -> list[str]:
    errors = []
    for alert in alerts:
        name = alert.get("alert", "unknown")
        annotations = alert.get("annotations", {})

        # Check presence
        url = annotations.get("runbook_url", "")
        if not url:
            errors.append(f"MISSING runbook_url: {name} in {alert['_file']}")
            continue

        # Skip template expressions ({{ ... }}) — can't resolve at CI time
        if "{{" in url:
            continue

        # Check reachability
        try:
            resp = requests.head(url, timeout=TIMEOUT_S, allow_redirects=True)
            if resp.status_code >= 400:
                errors.append(
                    f"BROKEN runbook_url ({resp.status_code}): {name} → {url}"
                )
        except requests.RequestException as e:
            errors.append(f"UNREACHABLE runbook_url: {name} → {url}: {e}")

    return errors

alerts = load_all_alerts(ALERT_DIR)
errors = check_runbook_links(alerts)
if errors:
    for e in errors:
        print(e, file=sys.stderr)
    sys.exit(1)
print(f"OK: {len(alerts)} alerts checked, all runbook_url annotations valid")
